(window.webpackJsonp=window.webpackJsonp||[]).push([[11,17],{519:function(n,s,t){},520:function(n,s,t){"use strict";t.r(s);var a={components:{},data:function(){return{}},props:{title:{type:String,default:""}},mounted:function(){},methods:{}},p=(t(521),t(71)),e=Object(p.a)(a,(function(){var n=this.$createElement;return(this._self._c||n)("div",{staticClass:"StyledTitle"},[this._v(this._s(this.title))])}),[],!1,null,"11b62ecb",null);s.default=e.exports},521:function(n,s,t){"use strict";var a=t(519);t.n(a).a},531:function(n,s,t){},560:function(n,s,t){"use strict";var a=t(531);t.n(a).a},572:function(n,s,t){"use strict";t.r(s);var a={components:{SectionTitle:t(520).default},data:function(){return{items:[{title:"相遇：幸运施了魔法~",datetime:"2019.10.06",desc:"<span>2020年4月底，我在豆瓣发现了她，第一次聊天即线下见面，所以称不上网恋。</span>\n          <span>那天我们聊了许久，感觉有说不完的话，不知不觉喝掉好几壶水呢~</span>\n          <span>虽然是首次接触，但就像认识了许久，这种熟悉又惊喜的感觉，使我们一点点向彼此靠近。</span>",picture:"https://s1.ax1x.com/2023/01/29/pSaLqSO.jpg"},{title:"相知：爱情中的模样~",datetime:"2019.11.18",desc:"<span>丘比特之箭射中了我们，空气都是甜甜的玉米味儿。</span>\n          <span>我们都爱大自然、且喜欢户外。</span>\n          <span>我们去永定河旁边的乡间小路探险，漫无目的地边走边玩，落日余晖下的她，真的好美。</span>\n          <span>我们一起爬好汉坡，蹭免费的植物园门票，欢呼雀跃的我们，像极了小孩子。</span>\n          <span>我们还挑战狗牙山10km穿越，有点冒险，很刺激，但她吓得不行，并严令禁止我再次挑战，她说：不想拿自己的生命冒险，当然也不想失去我。</span>\n          <span>我们喜欢看小说，喜欢从别人的故事中汲取人生智慧，甚至发表过一模一样的小说解读。</span>\n          <span>我们喜欢听歌疗愈，她听的歌大多痞痞的有点酷，我听得歌就是温柔偏大众了。</span>\n          <span>我们穿衣风格、消费习惯均高度相似，甚至脖子右侧有个一模一样的痣，上辈子的我们，可能是兄妹。</span>\n          <span>我们一起生活后，当然也免不了生活的摩擦。</span>\n          <span>我偏理性，她偏感性。</span>\n          <span>我是个慢性子，她是个急脾气。</span>\n          <span>我生气起来不爱说话，她生气起来爱飙狠话。</span>\n          <span>好在每次吵架我们都能冷静下来及时复盘，并学着去表达自己的感受，然后互相调整。</span>\n          <span>好的亲密关系是相处磨合出来的，我们愿意为了彼此去付出爱与精力，并时刻感恩。</span>",picture:"https://s1.ax1x.com/2023/01/29/pSaOVmj.jpg"},{title:"相守：心安即是归处~",datetime:"2022.05.27",desc:"<span>不管是租房，还是买房，只要心有所属，哪里就是家。</span>\n          <span>我们一起生活后，迫切的需要有自己的小家，自己的厨房</span>\n          <span>但问题是老家已有一个买来的住所，何不离京呢？</span>\n          <span>北京适合生存，不适合生活。</span>\n          <span>两人一拍即合，锅碗瓢盆打包一车搞定，吃完最后一顿火锅唱着歌，一路小跑就离京了。</span>\n          <span>我们的小家于5月份开始硬装，7月初着手软装。</span>\n          <span>从家徒四壁，到找装修公司，多次确认设计方案，然后灯具，家具，家电依次入场...</span>\n          <span>看到小家一点点变成我们想要的样子，真是发自内心的快乐。</span>\n          <span>对于这种突如其来的个人空间，我们沉浸在极大的新鲜感与兴奋感里，无法自拔。</span>\n          <span>我经常各个房间晃来晃去，她经常拿着盒尺量来量去，然后不约而同的相视，咯咯傻笑。</span>\n          <span>2022年5月27日，我们领证了！</span>\n          <span>只有那5分钟的紧张激动，很快就恢复平静。</span>\n          <span>可能在我心里，我们早就结婚了，这已然成为我们的日常生活。</span>\n          <span>我们以后将更珍惜彼此，小心呵护这份难得的感情~ 有福同享、有难同当，齐心协力、共同为我们的美好未来努力！</span>",picture:"https://s1.ax1x.com/2023/01/29/pSaOZ0s.jpg"}]}},mounted:function(){},methods:{}},p=(t(560),t(71)),e=Object(p.a)(a,(function(){var n=this,s=n.$createElement,t=n._self._c||s;return t("div",{staticClass:"StyledWrapper"},[t("section-title",{attrs:{title:"我们的故事"}}),n._v(" "),t("div",{staticClass:"tl"},n._l(n.items,(function(s,a){return t("ul",{key:a,staticClass:"items"},[t("li",{key:s.title,staticClass:"item"},[t("div",{staticClass:"pic"},[t("img",{attrs:{src:s.picture,alt:"picture"}})]),n._v(" "),t("i",{staticClass:"heart"},[n._v("💓")]),n._v(" "),t("div",{staticClass:"content"},[t("h4",{staticClass:"title"},[n._v(n._s(s.title))]),n._v(" "),t("time",{staticClass:"date"},[n._v(n._s(s.datetime))]),n._v(" "),t("p",{staticClass:"desc",domProps:{innerHTML:n._s(s.desc)}})])])])})),0)],1)}),[],!1,null,"afadfcf4",null);s.default=e.exports}}]);